const html = `
<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8">
  <meta name="viewport" content="width=device-width, initial-scale=1.0">
  <title>n8n Agent UI</title>
  <style>
    :root {
      --bg-color: #121212;
      --chat-bg: #1e1e1e;
      --user-msg: #ea4b71;
      --bot-msg: #2d2d2d;
      --text-color: #e0e0e0;
    }
    body { margin: 0; font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, Helvetica, Arial, sans-serif; background: var(--bg-color); color: var(--text-color); display: flex; justify-content: center; height: 100vh; }
    .chat-container { width: 100%; max-width: 600px; background: var(--chat-bg); display: flex; flex-direction: column; height: 100%; box-shadow: 0 0 20px rgba(0,0,0,0.5); }
    .header { padding: 20px; border-bottom: 1px solid #333; font-weight: bold; display: flex; align-items: center; gap: 10px; }
    .header-dot { width: 10px; height: 10px; background: #2ecc71; border-radius: 50%; }
    .messages { flex: 1; overflow-y: auto; padding: 20px; display: flex; flex-direction: column; gap: 15px; }
    .message { max-width: 80%; padding: 12px 16px; border-radius: 12px; line-height: 1.4; font-size: 15px; }
    .message.user { align-self: flex-end; background: var(--user-msg); color: white; border-bottom-right-radius: 2px; }
    .message.bot { align-self: flex-start; background: var(--bot-msg); color: var(--text-color); border-bottom-left-radius: 2px; }
    .input-area { padding: 20px; border-top: 1px solid #333; display: flex; gap: 10px; align-items: center; }
    input { flex: 1; padding: 12px; border-radius: 8px; border: 1px solid #444; background: #2d2d2d; color: white; outline: none; transition: border-color 0.2s; }
    input:focus { border-color: var(--user-msg); }
    button { padding: 12px 20px; border-radius: 8px; border: none; background: var(--user-msg); color: white; font-weight: bold; cursor: pointer; transition: opacity 0.2s; }
    button:hover { opacity: 0.9; }
    button:disabled { opacity: 0.5; cursor: not-allowed; }
    #mic-btn { background: #2d2d2d; border: 1px solid #555; font-size: 18px; padding: 10px 14px; flex-shrink: 0; }
    #mic-btn.recording { background: #ea4b71; border-color: #ea4b71; animation: pulse 1s infinite; }
    @keyframes pulse { 0%,100% { opacity: 1; } 50% { opacity: 0.5; } }
    .status { font-size: 12px; color: #888; padding: 0 20px 8px; min-height: 18px; }
  </style>
</head>
<body>
  <div class="chat-container">
    <div class="header"><div class="header-dot"></div>n8n Agent</div>
    <div class="messages" id="messages">
      <div class="message bot">Hello! I am your n8n assistant. You can type or use the 🎤 mic button to speak.</div>
    </div>
    <div class="status" id="status"></div>
    <form class="input-area" id="chat-form">
      <button type="button" id="mic-btn" title="Click to record">🎤</button>
      <input type="text" id="input" placeholder="Type or speak a message..." autocomplete="off" />
      <button type="submit" id="send-btn">Send</button>
    </form>
  </div>

  <script>
    const form = document.getElementById('chat-form');
    const input = document.getElementById('input');
    const messages = document.getElementById('messages');
    const sendBtn = document.getElementById('send-btn');
    const micBtn = document.getElementById('mic-btn');
    const status = document.getElementById('status');

    // ── API endpoints ─────────────────────────────
    const base = window.location.origin + '/webhook-test';
    const API_URL     = base + '/chat-response';
    const WHISPER_URL = base + '/whisper-proxy';
    const TTS_URL     = base + '/tts-proxy';

    // ── Helpers ───────────────────────────────────
    function setStatus(msg) { status.textContent = msg; }

    function addMessage(text, sender) {
      const div = document.createElement('div');
      div.className = 'message ' + sender;
      div.textContent = text;
      messages.appendChild(div);
      messages.scrollTop = messages.scrollHeight;
    }

    function setUIBusy(busy) {
      input.disabled = busy;
      sendBtn.disabled = busy;
      micBtn.disabled = busy;
    }

    // ── Send text to n8n, get reply, play TTS ─────
    async function sendMessage(text) {
      if (!text.trim()) return;
      addMessage(text, 'user');
      input.value = '';
      setUIBusy(true);
      setStatus('Agent is thinking...');

      try {
        const res = await fetch(API_URL, {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({ message: text })
        });
        const raw = await res.text();
        let reply = 'No response.';
        try {
          const data = JSON.parse(raw);
          reply = data.output || data.content || data.text || raw;
        } catch {
          reply = raw;
        }
        addMessage(reply, 'bot');

        setStatus('Generating audio...');
        const ttsRes = await fetch(TTS_URL + '?text=' + encodeURIComponent(reply));
        if (ttsRes.ok) {
          const audioBlob = await ttsRes.blob();
          const audioUrl = URL.createObjectURL(audioBlob);
          const audio = new Audio(audioUrl);
          audio.onended = () => URL.revokeObjectURL(audioUrl);
          await audio.play();
        }
        setStatus('');
      } catch (err) {
        console.error(err);
      } finally {
        setUIBusy(false);
        input.focus();
      }
    }

    // ── Text form submit ──────────────────────────
    form.addEventListener('submit', (e) => {
      e.preventDefault();
      sendMessage(input.value.trim());
    });

    // ── Voice recording ───────────────────────────
    let mediaRecorder = null;
    let audioChunks = [];

    micBtn.addEventListener('click', async () => {
      if (mediaRecorder && mediaRecorder.state === 'recording') {
        mediaRecorder.stop();
        return;
      }

      try {
        const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
        mediaRecorder = new MediaRecorder(stream);
        audioChunks = [];

        mediaRecorder.ondataavailable = (e) => audioChunks.push(e.data);

        mediaRecorder.onstop = async () => {
          micBtn.classList.remove('recording');
          micBtn.textContent = '🎤';
          stream.getTracks().forEach(t => t.stop());

          setStatus('Transcribing...');
          setUIBusy(true);

          try {
            const audioBlob = new Blob(audioChunks, { type: 'audio/webm' });
            const formData = new FormData();
            formData.append('audio_file', audioBlob, 'recording.webm');

            const whisperRes = await fetch(WHISPER_URL, {
              method: 'POST',
              body: formData
            });
            const whisperData = await whisperRes.json();
            const transcript = whisperData.text?.trim();

            if (transcript) {
              setStatus('');
              setUIBusy(false);
              await sendMessage(transcript);
            } else {
              setStatus("Couldn't hear anything — try again.");
              setUIBusy(false);
            }
          } catch (err) {
            setStatus('Whisper error: ' + err.message);
            setUIBusy(false);
            console.error(err);
          }
        };

        mediaRecorder.start();
        micBtn.classList.add('recording');
        micBtn.textContent = '⏹';
        setStatus('Recording... click ⏹ to stop');

      } catch (err) {
        setStatus('Mic access denied: ' + err.message);
        console.error(err);
      }
    });
  </script>
</body>
</html>
`;

return { html };

